# Core workflow engine with LLM integration
from typing import Any, Callable, Dict, List
from dataclasses import dataclass
from enum import Enum
import json

class NodeType(Enum):
    CODE = "code"
    LLM = "llm"
    CONDITION = "condition"
    PARALLEL = "parallel"
    LOOP = "loop"
    INTEGRATION = "integration"

@dataclass
class WorkflowNode:
    id: str
    type: NodeType
    config: Dict[str, Any]
    inputs: List[str]
    outputs: List[str]
    error_handling: Dict[str, Any]

class LLMNode:
    def __init__(self, model_config: Dict):
        self.model_config = model_config
        self.temperature = model_config.get("temperature", 0.7)
        self.max_tokens = model_config.get("max_tokens", 2000)

    async def execute(
        self,
        prompt: str,
        context: Dict[str, Any],
        tools: List[Dict] = None
    ) -> Dict[str, Any]:
        """Execute LLM with tool calling for structured responses"""
        messages = [
            {"role": "system", "content": self._build_system_prompt(context)},
            {"role": "user", "content": prompt}
        ]

        response = await self._call_llm(messages, tools)
        return {
            "text": response.content,
            "tool_calls": response.tool_calls,
            "usage": response.usage
        }

    def _build_system_prompt(self, context: Dict) -> str:
        return f"""You are an expert DevOps automation assistant.

Context:
- Environment: {context.get('environment', 'production')}
- Available tools: {json.dumps(context.get('available_tools', []), indent=2)}
- Constraints: {context.get('constraints', [])}

Respond with structured JSON when instructed."""

class CodeNode:
    def __init__(self, code: str, sandbox_config: Dict = None):
        self.code = code
        self.sandbox_config = sandbox_config or {}
        self.timeout = self.sandbox_config.get("timeout", 30)

    async def execute(self, context: Dict[str, Any]) -> Dict[str, Any]:
        """Execute custom Python code in isolated environment"""
        # Use RestrictedPython or similar for security
        sandbox = self._create_sandbox(context)

        try:
            result = await self._run_in_sandbox(self.code, sandbox)
            return {
                "success": True,
                "output": result,
                "execution_time": sandbox.get("execution_time")
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "error_type": type(e).__name__
            }

    def _create_sandbox(self, context: Dict) -> Dict:
        """Create restricted execution environment"""
        allowed_imports = {
            'json', 're', 'datetime', 'uuid',
            'requests', 'yaml', 'yaml'  # Add safe third-party libs
        }

        return {
            "globals": {
                **context,
                "__builtins__": self._safe_builtins(),
            },
            "allowed_modules": allowed_imports,
            "timeout": self.timeout
        }

    @staticmethod
    def _safe_builtins():
        """Restrict dangerous builtins"""
        dangerous = ['exec', 'eval', '__import__', 'open', 'compile']
        builtins = __builtins__.copy() if isinstance(__builtins__, dict) else vars(__builtins__)
        return {k: v for k, v in builtins.items() if k not in dangerous}
